query:
SELECT ?author WHERE { 
  ?publ a :Публикация;
            :название ?publ_name;
            :имеетАвтора ?author .
  FILTER(lcase(str(?publ_name)) =  "Оптимизация динамических систем с импульсными управлениями и ударными воздействиями") 
 }

SELECT DISTINCT ?org WHERE {  
  ?action a :Действие ; :имеетАктора ?author ; :исполняетсяВОрганизации ?org . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Ярмольчук Г Г") }

SELECT ?org WHERE { 
  ?action a :Действие ; 
             :имеетАктора ?author ;
             :исполняетсяВОрганизации ?org ; 
             :годНачала ?start ; :годЗавершения ?end .
  ?author :фамилия ?last_name . 
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Крафт Юрий Алексеевич")
  FILTER(?start >=  2000 && ?end <=  2012) }

SELECT DISTINCT ?coauthor WHERE { 
  ?pub a :Публикация ; 
    :имеетАвтора ?author ; 
    :имеетАвтора ?coauthor . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Казаков Василий Анатольевич")
  ?coauthor :фамилия ?colast_name.
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep))) }

SELECT DISTINCT ?coauthor WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author; :имеетАвтора ?coauthor ; 
    :классифицируется ?f1 .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Савицкий Олег Анатольевич")
  ?coauthor :фамилия ?colast_name.
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep))) 

?f1 a ?mf1 . 
?mf1 rdfs:subClassOf :ФакторКлассификации ; 
  :rank ?r1 . 
?f1 :название ?fname1 .  

FILTER(?r1 < 999)
FILTER(lcase(str(?fname1)) =  "Военное дело")
}

SELECT DISTINCT ?coauthor WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author; :имеетАвтора ?coauthor ; :годИздания ?year .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Копнина Наталья Валерьяновна")
  ?coauthor :фамилия ?colast_name.
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep)) && ?year >=  2009 && ?year <=  2023) }

SELECT DISTINCT ?coauthor WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author; :имеетАвтора ?coauthor ; :классифицируется ?f1 .
  ?pub :годИздания ?year . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Мартиросов А В")
  ?coauthor :фамилия ?colast_name.
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep)) && ?year >=  2007 && ?year <=  2013) 

?f1 a ?mf1 . 
?mf1 rdfs:subClassOf :ФакторКлассификации ; 
  :rank ?r1 . 
?f1 :название ?fname1 .  

FILTER(?r1 < 999)
FILTER(lcase(str(?fname1)) =  "Грибоводство")
}

SELECT DISTINCT ?org WHERE { 
  ?pub rdf:type :Статья . 
  ?pub :имеетАвтора ?author, ?coauthor .
  ?author :фамилия ?last_name .
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep)
  FILTER(lcase(str(?author_fio_sep)) =  "Филатов Владимир Иванович")

  ?act rdf:type :Действие . 
  ?act :порождает ?pub .
  ?act :имеетАктора ?coauthor . 

  ?coauthor :фамилия ?colast_name .
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep)) )
  ?act :исполняетсяВОрганизации ?org }

SELECT DISTINCT ?org WHERE { 
  ?pub rdf:type :Статья . 
  ?pub :имеетАвтора ?author, ?coauthor . 
  ?pub :годИздания ?year . 
  ?author :фамилия ?last_name .
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Овечкин Юрий Владимирович")
  ?coauthor :фамилия ?colast_name.
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep)) && ?year >=  2001 && ?year <=  2022)

  ?act rdf:type :Действие . 
  ?act :порождает ?pub .
  ?act :имеетАктора ?coauthor . 
  ?act :исполняетсяВОрганизации ?org }

SELECT ?start ?end WHERE { 
  ?action a :Действие ; :имеетАктора ?author .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Свихнушина Екатерина Андреевна").
  ?action :датаНачала ?start ; 
    :датаЗавершения ?end ; 
    :порождает ?res . 
  ?res :классифицируется ?f1 . 

  ?f1 a ?mf1 . 
  ?mf1 rdfs:subClassOf :ФакторКлассификации ; 
    :rank ?r1 . 
  ?f1 :название ?fname1 .  

  FILTER(?r1 < 999)
  FILTER(lcase(str(?fname1)) =  "Теория кодирования")
}

SELECT ?start ?end 
WHERE {
  ?action a :Действие ;
          :имеетАктора ?author ;
          :датаНачала ?start ;
          :датаЗавершения ?end ;
          :порождает ?res .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Сорокин Иван В.").

?res :классифицируется ?f1, ?f2 . 
?f1 a ?mf1 . 
?mf1 rdfs:subClassOf :ФакторКлассификации ; 
  :rank ?r1 . 
?f1 :название ?fname1 .  
?f2 a ?mf2 . 
?mf2 rdfs:subClassOf :ФакторКлассификации ; 
  :rank ?r2 . 
?f2 :название ?fname2 . 
FILTER(?r1 < ?r2 && ?r1 < 999 && ?r2 < 999)
FILTER(lcase(str(?fname1)) =  "Передача и обработка сигналов")
FILTER(lcase(str(?fname2)) =  "Теория дифференциальных игр")
}

SELECT ?pub WHERE { 
  ?pub a :Публикация ;
    :имеетАвтора author ; 
    :имеетАвтора author2 . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Гольдин Дмитрий Алексеевич").
  ?author2 :фамилия ?last_name2.
            OPTIONAL {?author2 :имя ?first_name2. }
            OPTIONAL {?author2 :отчество ?sec_name2. }
  BIND(CONCAT( ?last_name2, " ", COALESCE(?first_name2,""), " ", COALESCE(?sec_name2,"") ) as ?author_fio_sep2) 
  FILTER(lcase(str(?author_fio_sep2)) =  "Верхозина И О")}

SELECT ?factor WHERE { 
  ?p1 :имеетАвтора author ; :классифицируется ?factor . 
  ?p2 :имеетАвтора author2 ; :классифицируется ?factor . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Кравченко Александр Михайлович").
  ?author2 :фамилия ?last_name2.
            OPTIONAL {?author2 :имя ?first_name2. }
            OPTIONAL {?author2 :отчество ?sec_name2. }
  BIND(CONCAT( ?last_name2, " ", COALESCE(?first_name2,""), " ", COALESCE(?sec_name2,"") ) as ?author_fio_sep2) 
  FILTER(lcase(str(?author_fio_sep2)) =  "Лернер М. И.")}

SELECT ?coauthor WHERE { 
  ?pub1 :имеетАвтора ?author , ?coauthor . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Башалханов И А").
  ?coauthor :фамилия ?colast_name.
            OPTIONAL {?coauthor :имя ?cofirst_name. }
            OPTIONAL {?coauthor :отчество ?cosec_name. }
  BIND(CONCAT( ?colast_name, " ", COALESCE(?cofirst_name,""), " ", COALESCE(?cosec_name,"") ) as ?coauthor_fio_sep).
  FILTER(lcase(str(?coauthor_fio_sep)) != lcase(str(?author_fio_sep)))

  FILTER(?coauthor != ?author) 

  ?pub2 :имеетАвтора ?author2 , ?coauthor . 
  ?author2 :фамилия ?last_name2.
            OPTIONAL {?author2 :имя ?first_name2. }
            OPTIONAL {?author2 :отчество ?sec_name2. }
  BIND(CONCAT( ?last_name2, " ", COALESCE(?first_name2,""), " ", COALESCE(?sec_name2,"") ) as ?author_fio_sep2) 
  FILTER(lcase(str(?author_fio_sep2)) =  "Минаев Эдуард Сергеевич")

  FILTER(?coauthor != ?author2) }

SELECT DISTINCT ?org WHERE { ?act1 a :Действие ; :имеетАктора ?author ; :исполняетсяВОрганизации ?org . 
?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
FILTER(lcase(str(?author_fio_sep)) =  "Плотникова В Н").

?act2 a :Действие ; :имеетАктора ?author2 ; :исполняетсяВОрганизации ?org .
?author2 :фамилия ?last_name2.
            OPTIONAL {?author2 :имя ?first_name2. }
            OPTIONAL {?author2 :отчество ?sec_name2. }
BIND(CONCAT( ?last_name2, " ", COALESCE(?first_name2,""), " ", COALESCE(?sec_name2,"") ) as ?author_fio_sep2) 
FILTER(lcase(str(?author_fio_sep2)) =  "Каиркенов Х. К.") }

SELECT ?pub ?year WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author ; :годИздания ?year . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Королев В С").
  FILTER(?year >=  2003 && ?year <=  2015) }

SELECT ?pub ?year WHERE { 
  ?pub a :Статья ; :имеетАвтора ?author ; :годИздания ?year .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Насатуева Соелма Номтоевна").
  FILTER(?year >=  2008 && ?year <=  2017) }

SELECT ?pub WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Rahul Reddy Nadikattu") }

SELECT DISTINCT ?keyword WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author ; :ключевоеСлово ?keyword .
  ?author :фамилия ?last_name .
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Парыгин Данила Сергеевич") }

SELECT DISTINCT ?keyword WHERE { 
  ?action a :Действие ; :имеетАктора ?author ; :исполняетсяВОрганизации ?org; :порождает ?pub . 
  ?pub a :Публикация ; :ключевоеСлово ?keyword . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Купцов Петр Дмитриевич") 

  ?org :название ?name.
  FILTER(lcase(str(?name)) =  "ФГБУ Арктический и антарктический научно-исследовательский институт") }

SELECT ?orcid ?elibrary ?scopus WHERE { 
  ?author a :Персона .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Сейфи Н Т") 
  OPTIONAL { ?author :ORCID ?orcid } 
  OPTIONAL { ?author :eLibraryId ?elibrary } 
  OPTIONAL { ?author :scopusId ?scopus } }

SELECT ?title WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author ; :название ?title . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Усмонов Ботир Ш") 
  FILTER NOT EXISTS { ?pub :имеетАвтора ?other . FILTER(?other != ?author) } }

SELECT (COUNT(DISTINCT ?pub) AS ?count) WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Прокопенков Александр Александрович")  }

SELECT (COUNT(DISTINCT ?pub) AS ?count) WHERE { 
  ?pub a :Статья ; :имеетАвтора ?author .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Савченко Юрий Васильевич") }

SELECT (COUNT(DISTINCT ?pub) AS ?count) WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author ; :имеетАвтора ?coauthor .
  ?author :фамилия ?last_name .
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Крылов Павел Андреевич")
  FILTER(?coauthor != ?author) }

SELECT DISTINCT ?title WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author ; :имеетАвтора ?coauthor ; :название ?title . 
  ?author :фамилия ?last_name .
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Кадэй Тхэй -")
  FILTER(?coauthor != ?author) }

SELECT ?title WHERE { 
  ?pub a :Публикация ; :имеетАвтора ?author ; :годИздания ?year ; :название ?title . 
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Бородин А Д")
  FILTER(?year >=  2003 && ?year <=  2015) }

ASK WHERE { 
  ?author (^:имеетАвтора/:имеетАвтора)+ ?author2 .
  ?author :фамилия ?last_name.
            OPTIONAL {?author :имя ?first_name. }
            OPTIONAL {?author :отчество ?sec_name. }
  BIND(CONCAT( ?last_name, " ", COALESCE(?first_name,""), " ", COALESCE(?sec_name,"") ) as ?author_fio_sep) 
  FILTER(lcase(str(?author_fio_sep)) =  "Гохберг Л М")
  ?author2 :фамилия ?last_name2.
            OPTIONAL {?author2 :имя ?first_name2. }
            OPTIONAL {?author2 :отчество ?sec_name2. }
  BIND(CONCAT( ?last_name2, " ", COALESCE(?first_name2,""), " ", COALESCE(?sec_name2,"") ) as ?author_fio_sep2) 
  FILTER(lcase(str(?author_fio_sep2)) =  "Шибаев Максим Станиславович") }

SELECT ?start ?end
WHERE {
  ?action a :Действие ;
          :имеетАктора :person_764 ;
          :датаНачала ?start ;
          :датаЗавершения ?end ;
          :порождает ?res .
  ?res :классифицируется :class_factor_8613 ,:class_factor_6901 .
 :class_factor_8613 a ?metaFactor1 . ?metaFactor1 rdfs:subClassOf :ФакторКлассификации .
 :class_factor_6901 a ?metaFactor2 . ?metaFactor2 rdfs:subClassOf :ФакторКлассификации .
  ?metaFactor1 :rank ?rank1 .
  ?metaFactor2 :rank ?rank2 .
