            :имеетАктора ?person ;
            :имеетРоль :автор ;
            :исполняетсяВОрганизации ?org ;
            :порождает ?pub .
    ?org :название ?name .  
    FILTER(lcase(str(?name)) =  "Институт молекулярной и клеточной биологии СО РАН (ИМКБ СО РАН) ")
    ?pub rdf:type :Публикация
  }
  GROUP BY ?person
  HAVING(?pubcount >  3)
}
ORDER BY DESC(?pubcount)

